import{_ as l,c as i,o as r,ae as a}from"./chunks/framework.CMFi8ROq.js";const d=JSON.parse('{"title":"Fiber 架构","description":"","frontmatter":{},"headers":[],"relativePath":"note/framework/react/Fiber架构.md","filePath":"note/framework/react/Fiber架构.md","lastUpdated":null}'),t={name:"note/framework/react/Fiber架构.md"};function p(o,e,c,n,b,s){return r(),i("div",null,e[0]||(e[0]=[a('<h1 id="fiber-架构" tabindex="-1">Fiber 架构 <a class="header-anchor" href="#fiber-架构" aria-label="Permalink to &quot;Fiber 架构&quot;">​</a></h1><p>在 React 16 版本， 官方对底层进行了一次“推倒重来”式的重构。</p><ul><li>在 React 15 时代，架构被称为 Stack Reconciler（栈协调器）或 栈架构，它是同步堆栈渲染架构</li><li>在 React 16 时代，架构被称为 Fiber 架构，它是一个异步并发架构。</li></ul><p>本次重构的核心核心目的是解决下面几个问题：</p><h2 id="架构的三大核心模块" tabindex="-1">架构的三大核心模块 <a class="header-anchor" href="#架构的三大核心模块" aria-label="Permalink to &quot;架构的三大核心模块&quot;">​</a></h2><p>为了实现高效、可中断的渲染，Fiber 架构将工作流程拆分成了三个独立的部分：</p><ul><li><p>Scheduler（调度器）</p><ul><li><p>职责：决定什么时候干活。它会监控浏览器的空闲时间，并在有高优先级任务（如用户输入）时，中断当前的渲染工作。</p></li><li><p>核心机制：使用了类似 requestIdleCallback 的机制，但在兼容性和触发频率上做了大量优化，目前使用的是 <strong>Lane 模型</strong> 来区分任务优先级。</p></li></ul></li><li><p>Reconciler(协调器)</p><ul><li>职责：它负责找出 UI 哪些部分需要改变。对比新旧虚拟 DOM（即我们聊到的 Fiber 树），并给有变化的 Fiber 节点打上标记（如 Placement、Update、Deletion）。</li><li>核心机制：在内存中构建 workInProgress 树（双缓存 Fiber 树）。由于这个过程是在内存中进行的，且是基于 Fiber 链表结构，所以它是可以随时被中断的。</li></ul></li><li><p>Renderer（渲染器）</p><ul><li>职责：负责把协调器的计算结果真正画到屏幕上。根据 Reconciler 打的标记，执行具体的宿主操作。</li><li>多样性：不同的平台有不同的渲染器。 <ul><li>react-dom：负责浏览器 DOM。</li><li>react-native：负责手机原生 UI。</li><li>react-art：负责 Canvas/SVG。</li></ul></li></ul></li></ul><h2 id="fiber-节点" tabindex="-1">Fiber 节点 <a class="header-anchor" href="#fiber-节点" aria-label="Permalink to &quot;Fiber 节点&quot;">​</a></h2><p>你可以在这里看到 <a href="https://github.com/facebook/react/blob/1fb18e22ae66fdb1dc127347e169e73948778e5a/packages/react-reconciler/src/ReactFiber.new.js#L117" target="_blank" rel="noreferrer">Fiber 的数据结构</a>。Fiber 的三重身份:</p><ol><li><p>作为数据结构</p><p>每一个 Fiber 节点都对应一个组件或 DOM 元素。它本质上是一个普通的 JS 对象，存储:</p><ul><li>组件信息：类型（type）、属性（pendingProps）。</li><li>状态信息：存储组件状态，指向的是 Hooks 链表。</li><li>副作用信息：记录该节点是否需要插入、更新或删除（flags）。</li></ul></li><li><p>作为指针链表</p><p>传统的树结构通常用 children 存储子节点，但 Fiber 为了方便中断和恢复，使用了三指针链表记录树节点关系，并基于此遍历和更新组件树。分别是:</p><ul><li><p>child：指向子节点。</p></li><li><p>sibling：指向兄弟节点。</p></li><li><p>return：指向父节点。</p></li></ul><p>这种结构允许 React 在处理完一个节点后，通过指针快速找到下一个任务，或者在中断后重新找回位置。</p></li><li><p>作为工作单元（调度核心）</p><p>每个 Fiber 节点都是一个待处理的任务。React 的 Scheduler（调度器） 会根据优先级来决定先处理哪个 Fiber。</p><ul><li><p>它会利用浏览器的空闲时间（类似于 requestIdleCallback 的机制）来遍历 Fiber 树。</p></li><li><p>如果这时有更高优先级的任务（如用户输入），React 会暂停当前的 Fiber 构建，先去处理交互。</p></li></ul></li></ol>',10)]))}const f=l(t,[["render",p]]);export{d as __pageData,f as default};
